blocks.body:
{
    "level": "B1–B2",
    "intro": "W tym temacie poznasz <strong>konstrukcję sprawczą</strong> - sposób powiedzenia, że ​​ktoś inny wykonuje jakąś czynność za Ciebie (zwykle za pieniądze lub na Twoją prośbę).",
    "rules": [
        {
            "label": "Mieć",
            "color": "emerald",
            "text": "<strong>mieć + obiekt + V3</strong> (bardziej formalnie):",
            "example": "I had my car repaired. — Мені відремонтували машину."
        },
        {
            "label": "Dostawać",
            "color": "blue",
            "text": "<strong>pobierz + obiekt + V3</strong> (bardziej potoczny):",
            "example": "I got my hair cut. — Мене підстригли."
        },
        {
            "label": "Wartość",
            "color": "amber",
            "text": "Ktoś <strong>inny</strong> wykonuje za Ciebie czynność:",
            "example": "I don't cut my hair myself — a hairdresser does it."
        }
    ]
}

{
    "title": "1. Sprawczy, aktywny i pasywny",
    "intro": "Porównanie trzech projektów:",
    "rows": [
        {
            "en": "Active: I repaired my car.",
            "ua": "Naprawiłem samochód.",
            "note": "Zrobiłem to sam."
        },
        {
            "en": "Passive: My car was repaired.",
            "ua": "Mój samochód został naprawiony.",
            "note": "Ktoś to zrobił (nie wiadomo kto)."
        },
        {
            "en": "Causative: I had my car repaired.",
            "ua": "Mój samochód został naprawiony.",
            "note": "Zamówiłem usługę (ktoś zrobił to za mnie)."
        }
    ],
    "warning": "📌 Sprawca podkreśla, że ​​zorganizowaliśmy przeprowadzenie akcji, a nie zrobiliśmy tego sami!"
}

{
    "title": "2. Zajmij się czymś w różnym czasie",
    "intro": "Czasownik <strong>have</strong> zmienia się według czasu:",
    "items": [
        {
            "label": "Czas teraźniejszy prosty",
            "title": "mieć/ma + obiekt + V3",
            "subtitle": "Co miesiąc strzygę włosy."
        },
        {
            "label": "Czas przeszły prosty",
            "title": "miał + obiekt + V3",
            "subtitle": "Wczoraj oddała samochód do serwisu."
        },
        {
            "label": "Przyszłość prosta",
            "title": "będzie miał + obiekt + V3",
            "subtitle": "Jutro oddam garnitur do czyszczenia."
        },
        {
            "label": "Czas teraźniejszy idealny",
            "title": "mieć/miał + obiekt + V3",
            "subtitle": "Malowaliśmy nasz dom."
        },
        {
            "label": "Czas teraźniejszy ciągły",
            "title": "mam/jest/mam + obiekt + V3",
            "subtitle": "Remontują kuchnię."
        },
        {
            "label": "Czasowniki modalne",
            "title": "modalne + mają + obiekt + V3",
            "subtitle": "Powinieneś przebadać swój wzrok."
        }
    ]
}

{
    "title": "3. Typowe sytuacje dla sprawcy",
    "sections": [
        {
            "label": "Usługi / usługa",
            "color": "emerald",
            "description": "Kiedy <strong>zamawiamy usługę</strong>:",
            "examples": [
                {
                    "en": "I had my hair cut yesterday.",
                    "ua": "Wczoraj ścięłam włosy."
                },
                {
                    "en": "She has her nails done every week.",
                    "ua": "Co tydzień robi sobie manicure."
                },
                {
                    "en": "We had the house painted last month.",
                    "ua": "W zeszłym miesiącu malowaliśmy nasz dom."
                }
            ]
        },
        {
            "label": "Naprawa/konserwacja",
            "color": "blue",
            "description": "W przypadku <strong>naprawy i konserwacji</strong>:",
            "examples": [
                {
                    "en": "I need to have my car serviced.",
                    "ua": "Muszę oddać samochód do przeglądu."
                },
                {
                    "en": "They had their roof repaired.",
                    "ua": "Naprawiono ich dach."
                },
                {
                    "en": "You should have your brakes checked.",
                    "ua": "Powinieneś sprawdzić hamulce."
                }
            ]
        },
        {
            "label": "Usługi medyczne",
            "color": "amber",
            "description": "W przypadku procedur <strong>medycznych</strong>:",
            "examples": [
                {
                    "en": "I had my eyes tested last week.",
                    "ua": "W zeszłym tygodniu sprawdzałem wzrok."
                },
                {
                    "en": "She needs to have her teeth cleaned.",
                    "ua": "Musi umyć zęby (u dentysty)."
                },
                {
                    "en": "He had his blood pressure checked.",
                    "ua": "Zmierzono mu ciśnienie krwi."
                }
            ]
        },
        {
            "label": "Dostawa/montaż",
            "color": "rose",
            "description": "W przypadku <strong>dostawy i instalacji</strong>:",
            "examples": [
                {
                    "en": "We had a new kitchen installed.",
                    "ua": "Zamontowano dla nas nową kuchnię."
                },
                {
                    "en": "They had the furniture delivered.",
                    "ua": "Dostarczono im meble."
                },
                {
                    "en": "I had the internet connected yesterday.",
                    "ua": "Wczoraj miałem połączenie z internetem."
                }
            ]
        }
    ]
}

{
    "title": "4. Zrób coś vs Zrób coś",
    "intro": "Obie formy mają podobne znaczenie, ale istnieją różnice:",
    "rows": [
        {
            "en": "Have: I had my car repaired.",
            "ua": "Mój samochód został naprawiony.",
            "note": "Bardziej formalny, neutralny."
        },
        {
            "en": "Get: I got my car repaired.",
            "ua": "Mój samochód został naprawiony.",
            "note": "Bardziej rozmowny, podkreśla wysiłek."
        },
        {
            "en": "Have: She had her dress made.",
            "ua": "Sukienka została stworzona dla niej.",
            "note": "Standardowa usługa."
        },
        {
            "en": "Get: She finally got her dress made.",
            "ua": "W końcu powstała dla niej sukienka.",
            "note": "Podkreśla, że ​​nie było to łatwe."
        }
    ],
    "warning": "📌 Get często podkreśla, że ​​trzeba było się napracować, żeby coś osiągnąć!"
}

{
    "title": "5. Negatywna przyczyna (nieprzyjemne zdarzenia)",
    "sections": [
        {
            "label": "Negatywne zdarzenia",
            "color": "rose",
            "description": "Czasownika sprawczego używamy także w odniesieniu do <strong>nieprzyjemnych wydarzeń</strong>, które nam się przytrafiły:",
            "examples": [
                {
                    "en": "I had my wallet stolen.",
                    "ua": "Skradziono mi portfel."
                },
                {
                    "en": "She had her car broken into.",
                    "ua": "Włamano się do jej samochodu."
                },
                {
                    "en": "They had their house burgled.",
                    "ua": "Okradziono ich (włamano się do domu)."
                }
            ]
        },
        {
            "label": "Różnica tkwi w kontekście",
            "color": "amber",
            "description": "Kontekst określa, czy jest to <strong>usługa</strong>, czy <strong>uciążliwość</strong>:",
            "examples": [
                {
                    "en": "I had my hair cut. (послуга)",
                    "ua": "Strzyżyłem się (u fryzjera)."
                },
                {
                    "en": "I had my bag stolen. (неприємність)",
                    "ua": "Skradziono mi torbę."
                },
                {
                    "en": "She had her phone repaired. (послуга)",
                    "ua": "Jej telefon został naprawiony."
                }
            ]
        }
    ]
}

{
    "title": "6. Zastrzeżenia i pytania",
    "intro": "Formowanie zastrzeżeń i pytań w sprawie sprawczej:",
    "items": [
        {
            "label": "Sprzeciw (mają)",
            "title": "nie ma/nie ma/nie miał + obj + V3",
            "subtitle": "Nie naprawiałem samochodu."
        },
        {
            "label": "odmowa (otrzymania)",
            "title": "nie/nie/nie dostaje + obj + V3",
            "subtitle": "Nie poprawiła sobie fryzury."
        },
        {
            "label": "pytanie (mają)",
            "title": "Czy/Robi/Czy + podmiot + ma + obj + V3?",
            "subtitle": "Czy serwisowałeś swój samochód?"
        },
        {
            "label": "pytanie (dostać)",
            "title": "Zrób/Robi/Zrobił + subj + get + obj + V3?",
            "subtitle": "Czy udało jej się uszyć sukienkę?"
        },
        {
            "label": "Jakie pytanie",
            "title": "Wh + zrobić/robi/zrobił + subj + mieć/dostać + obj + V3?",
            "subtitle": "Gdzie ścięłaś włosy?"
        },
        {
            "label": "Przyszły",
            "title": "Will + subj + mieć/dostać + obj + V3?",
            "subtitle": "Czy dokończysz raport?"
        }
    ]
}

{
    "title": "7. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Używanie bezokolicznika zamiast V3.",
            "wrong": "I had my car to repair.",
            "right": "✅ I had my car repaired."
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Przekazywanie obiektu pomiędzy Have/get i V3.",
            "wrong": "I had repaired my car.",
            "right": "✅ I had my car repaired."
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Pomieszanie przyczyny ze stanem aktywnym.",
            "wrong": "I had cut my hair. (= я сам підстригся)",
            "right": "✅ I had my hair cut. (= мене підстригли)"
        },
        {
            "label": "Błąd 4",
            "color": "rose",
            "title": "Nieprawidłowa kolejność słów.",
            "wrong": "I had repaired my car yesterday.",
            "right": "✅ I had my car repaired yesterday."
        }
    ]
}
